import os
def get_size(p='.'):
    total = 0
    for entry in os.scandir(p):
        if entry.is_file(): total += entry.stat().st_size
        elif entry.is_dir(): total += get_size(entry.path)
    return total
size_mb = get_size() / (1024*1024)
if size_mb > 500: print(f'Xəbərdarlıq: {size_mb:.2f} MB yer tutur!')
else: print('Həcm normaldır.')

